    writeFileSync(staleScriptPath, "print('old runner')\n", "utf8");
    writeFileSync(
      wrapperPath,
      [
        "#!/usr/bin/env bash",
        "set -euo pipefail",
        'SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"',
        'python "${SCRIPT_DIR}/run_condition_grid_study.py" --metrics-path "${PWD}/metrics.json"'
      ].join("\n"),
      "utf8"
    );

