  it("bridges generated train/eval helpers into baseline-first condition execution helpers", async () => {
    const workspace = mkdtempSync(path.join(os.tmpdir(), "autolabos-condition-train-eval-"));
    tempDirs.push(workspace);
    const scriptPath = path.join(workspace, "runner.py");
    writeFileSync(
      scriptPath,
      [
        "from __future__ import annotations",
        "",
        "import contextlib",
        "import gc",
        "import logging",
        "from typing import Any, Dict, Mapping, Optional",
        "",
        "LOGGER = logging.getLogger(__name__)",
        "torch = None",
        "",
        "class FakeContext:",
        "    def as_dict(self):",
        "        return {'output_dir': 'out', 'arc_eval_examples': 2, 'benchmark_task_b_eval_examples': 2}",
        "",
        "def _condition_marker(spec: Any, *, default: Optional[str] = None) -> str:",
        "    if isinstance(spec, Mapping):",
        "        return str(spec.get('marker') or default or 'unknown')",
        "    return str(default or 'unknown')",
        "",
        "def prepare_dataset_bundle(runtime: Mapping[str, Any], *, logger: Optional[logging.Logger] = None) -> Dict[str, Any]:",
        "    return {'train_records': [{'prompt': 'a'}], 'eval_tasks': {'benchmark_task_a': [{'answer_label': 'A'}]}}",
        "",
        "def load_tokenizer_and_model(model_id: str, runtime: Mapping[str, Any], condition_marker: str):",
        "    return object(), object(), 'cpu', {'condition_marker': condition_marker, 'model_id': model_id}",
        "",
        "def evaluate_condition_result(condition_result: Dict[str, Any], eval_bundle: Mapping[str, Any], *, logger: Optional[logging.Logger] = None, max_examples_per_task: Optional[int] = None):",
        "    assert condition_result.get('model') is not None",
        "    assert condition_result.get('tokenizer') is not None",
        "    condition_result['average_accuracy'] = 0.5",
        "    condition_result['evaluation'] = {'status': 'completed', 'tasks': eval_bundle}",
        "    condition_result['status'] = 'completed'",
        "    return condition_result",
        "",
        "def run_training_for_condition(condition: Any, runtime: Optional[Mapping[str, Any]], selected_model_id: str, train_examples: Any) -> Dict[str, Any]:",
        "    try:",
        "        model = object()",
        "        tokenizer = object()",
        "        device = 'cpu'",
        "        train_result = {'status': 'completed', 'condition_marker': _condition_marker(condition), 'model_id': selected_model_id}",
        "        return train_result",
        "    except Exception as exc:",
        "        raise exc",
        "",
        "def _call_first_matching_helper(helper_names, *, kwarg_variants, positional_variants):",
        "    for helper_name in helper_names:",
        "        helper = globals().get(helper_name)",
        "        if callable(helper):",
        "            return helper(**kwarg_variants[0])",
        "    raise RuntimeError(f'No matching helper was found among candidates: {list(helper_names)}')",
        "",
        "def _execute_condition(spec: Mapping[str, Any], role: str):",
        "    helper_names = ['run_condition_experiment', 'run_single_condition', 'execute_condition', 'train_and_evaluate_condition', 'run_condition', 'execute_training_condition']",
        "    if role == 'baseline':",
        "        helper_names = ['run_baseline_condition'] + helper_names",
        "    return _call_first_matching_helper(",
        "        helper_names,",
        "        kwarg_variants=[{'context': FakeContext(), 'condition': spec, 'selected_model_id': 'fake-model', 'preflight_result': {}}],",
        "        positional_variants=[],",
        "    )",
        "",
        "def main():",
        "    baseline = _execute_condition({'marker': 'baseline'}, 'baseline')",
        "    tuned = _execute_condition({'marker': 'baseline_condition'}, 'tuned_condition')",
        "    assert baseline['status'] == 'success'",
        "    assert tuned['status'] == 'success'",
        "    assert baseline['average_accuracy'] == 0.5",
        "    assert tuned['average_accuracy'] == 0.5",
        "    assert 'model' not in baseline",
        "    assert 'tokenizer' not in tuned",
        "    return 0",
        "",
        "if __name__ == '__main__':",
        "    raise SystemExit(main())",
        ""
      ].join("\n"),
      "utf8"
    );

    expect(() => execFileSync("python3", [scriptPath], { cwd: workspace })).toThrow(
      /No matching helper/
    );

    const repair = await repairPythonConditionTrainEvalHelperBridgeSurface(scriptPath);
    const repairedSource = readFileSync(scriptPath, "utf8");

    expect(repair.repaired).toBe(true);
    expect(repairedSource).toContain("_autolabos_train_eval_condition_bridge_marker");
    expect(repairedSource).toContain("def run_baseline_condition(");
    expect(repairedSource).toContain("def run_condition_experiment(");
    execFileSync("python3", [scriptPath], { cwd: workspace });
  });

  it("accepts answer_label as an evaluation gold-label alias", async () => {
    const workspace = mkdtempSync(path.join(os.tmpdir(), "autolabos-answer-label-alias-"));
    tempDirs.push(workspace);
    const scriptPath = path.join(workspace, "runner.py");
    writeFileSync(
      scriptPath,
      [
        "from typing import Any, Dict, Optional, Sequence",
        "",
        "def _coerce_label_index(example: Dict[str, Any], choices: Sequence[Dict[str, str]]) -> Optional[int]:",
        "    raw_label = None",
        "    for key in (\"label\", \"answer\", \"answerKey\", \"gold\", \"target\", \"correct_index\"):",
        "        if key in example and example[key] not in (None, \"\"):",
        "            raw_label = example[key]",
        "            break",
        "    if raw_label is None:",
        "        return None",
        "    upper_label = str(raw_label).strip().upper()",
        "    for index, choice in enumerate(choices):",
        "        if str(choice.get(\"label\", \"\")).strip().upper() == upper_label:",
        "            return index",
        "    return None",
        "",
        "def main():",
        "    choices = [{'label': 'A'}, {'label': 'B'}]",
        "    assert _coerce_label_index({'answer_label': 'B'}, choices) == 1",
        "    return 0",
        "",
        "if __name__ == '__main__':",
        "    raise SystemExit(main())",
        ""
      ].join("\n"),
      "utf8"
    );

    expect(() => execFileSync("python3", [scriptPath], { cwd: workspace })).toThrow();

    const repair = await repairPythonEvaluationAnswerLabelAliasSurface(scriptPath);
    const repairedSource = readFileSync(scriptPath, "utf8");

    expect(repair.repaired).toBe(true);
    expect(repairedSource).toContain('"answer_label"');
    execFileSync("python3", [scriptPath], { cwd: workspace });
  });

  it("repairs broad compatible-call adapters that reintroduce filtered kwargs and duplicate metrics args", async () => {
    const workspace = mkdtempSync(path.join(os.tmpdir(), "autolabos-implement-compatible-adapter-"));
    tempDirs.push(workspace);
    process.chdir(workspace);
    const paths = resolveAppPaths(workspace);
    await ensureScaffold(paths);

    const runStore = new RunStore(paths);
    const run = await runStore.createRun({
      title: "Compatible Adapter Runtime Failure",
      topic: "runtime helper adapter validation",
      constraints: ["recent"],
      objectiveMetric: "accuracy"
    });

    const runDir = path.join(workspace, ".autolabos", "runs", run.id);
    mkdirSync(runDir, { recursive: true });
    const scriptPath = path.join(runDir, "experiment.py");
    writeFileSync(
      scriptPath,
      [
        "from __future__ import annotations",
        "",
        "import inspect",
        "from typing import Any, Callable, Mapping",
        "",
        "def _call_compatible(fn: Callable[..., Any], *args: Any, **kwargs: Any) -> Any:",
        "    \"\"\"Call a helper while filtering keyword arguments it does not accept.\"\"\"",
        "    try:",
        "        signature = inspect.signature(fn)",
        "        parameters = signature.parameters",
        "        accepts_var_kwargs = any(",
        "            parameter.kind == inspect.Parameter.VAR_KEYWORD for parameter in parameters.values()",
        "        )",
        "        if accepts_var_kwargs:",
        "            return fn(*args, **kwargs)",
        "        filtered_kwargs = {key: value for key, value in kwargs.items() if key in parameters}",
        "        return fn(*args, **filtered_kwargs)",
        "    except (TypeError, ValueError):",
        "        return fn(*args, **kwargs)",
        "",
        "def write_metrics_json(metrics: Mapping[str, Any], metrics_path: str) -> None:",
        "    pass",
        "",
        "def _autolabos_write_metrics(metrics: Mapping[str, Any], metrics_path: str) -> None:",
        "    writer = write_metrics_json",
        "    _call_compatible(writer, metrics, metrics_path, metrics=metrics, path=metrics_path, output_path=metrics_path)",
        ""
      ].join("\n"),
      "utf8"
    );

    const manager = new ImplementSessionManager({
      config: createTestConfig(),
      codex: {} as CodexNativeClient,
      aci: new LocalAciAdapter(),
      eventStream: new InMemoryEventStream(),
      runStore,
      workspaceRoot: workspace
    });

    const verifier = manager as unknown as {
      verifyAttempt(
        attempt: Record<string, unknown>,
        abortSignal: AbortSignal | undefined,
        runId: string,
        attemptNumber: number
      ): Promise<{ status: string; failure_type?: string; summary: string }>;
    };

    const report = await verifier.verifyAttempt(
      {
        verifyReport: { status: "not_run" },
        testCommand: `python3 -m py_compile ${JSON.stringify(scriptPath)}`,
        scriptPath,
        workingDir: runDir,
        workspaceRoot: workspace,
        localization: {
          selected_files: [scriptPath],
          candidates: []
        }
      },
      undefined,
      run.id,
      1
    );

    const repairedSource = readFileSync(scriptPath, "utf8");
    expect(report.status).toBe("pass");
    expect(repairedSource).toContain("filtered_kwargs = {key: value for key, value in kwargs.items() if key in parameters}");
    expect(repairedSource).not.toContain(
      "return fn(*args, **filtered_kwargs)\n    except (TypeError, ValueError):\n        return fn(*args, **kwargs)"
    );
    expect(repairedSource).not.toContain("_call_compatible(writer, metrics, metrics_path, metrics=metrics");
    expect(repairedSource).toContain("_call_compatible(writer, metrics=metrics, metrics_path=metrics_path");
  });

  it("repairs orchestration wrappers that reparse Namespace args and omit workflow datasets", async () => {
    const workspace = mkdtempSync(path.join(os.tmpdir(), "autolabos-implement-orchestration-args-"));
    tempDirs.push(workspace);
    const scriptPath = path.join(workspace, "experiment.py");
    writeFileSync(
      scriptPath,
      [
        "from __future__ import annotations",
        "",
        "import argparse",
        "import inspect",
        "from typing import Any, Dict, Mapping, Optional, Sequence",
        "",
        "DEFAULT_METRICS_PATH = 'metrics.json'",
        "DEFAULT_RESULTS_PATH = 'results.json'",
        "DEFAULT_BASE_MODEL = 'tiny-model'",
        "DEFAULT_SEED = 42",
        "DEFAULT_MAX_TRAIN_EXAMPLES = 2",
        "DEFAULT_MAX_EVAL_EXAMPLES_PER_BENCHMARK = 1",
        "DEFAULT_MAX_NEW_TOKENS = 4",
        "MAX_ALLOWED_TRAIN_EXAMPLES = 4",
        "MAX_ALLOWED_EVAL_EXAMPLES_PER_BENCHMARK = 2",
        "LOCKED_RECIPE_ORDER = ['lora']",
        "ADAPTER_RECIPES = [{'id': 'lora'}]",
        "",
        "def build_arg_parser():",
        "    parser = argparse.ArgumentParser()",
        "    parser.add_argument('--metrics-path', default=DEFAULT_METRICS_PATH)",
        "    parser.add_argument('--model-name', default=DEFAULT_BASE_MODEL)",
        "    return parser",
        "",
        "def _get_arg(args, name, default=None):",
        "    return getattr(args, name, default)",
        "",
        "def _parse_orchestration_args(argv: Optional[Sequence[str]] = None) -> argparse.Namespace:",
        "    parser = build_arg_parser()",
        "    parsed = parser.parse_args(argv)",
        "    if not hasattr(parsed, 'seed'):",
        "        setattr(parsed, 'seed', DEFAULT_SEED)",
        "    if not hasattr(parsed, 'max_train_examples'):",
        "        setattr(parsed, 'max_train_examples', DEFAULT_MAX_TRAIN_EXAMPLES)",
        "    if not hasattr(parsed, 'max_eval_examples_per_benchmark'):",
        "        setattr(parsed, 'max_eval_examples_per_benchmark', DEFAULT_MAX_EVAL_EXAMPLES_PER_BENCHMARK)",
        "    if not hasattr(parsed, 'max_new_tokens'):",
        "        setattr(parsed, 'max_new_tokens', DEFAULT_MAX_NEW_TOKENS)",
        "    return parsed",
        "",
        "def _initialize_orchestration_runtime(args: argparse.Namespace) -> Dict[str, Any]:",
        "    return {'device': 'cpu', 'cache_dir': '.', 'output_dir': '.'}",
        "",
        "def _call_with_compatible_signature(func: Any, **kwargs: Any) -> Any:",
        "    signature = inspect.signature(func)",
        "    parameters = signature.parameters",
        "    if any(parameter.kind == inspect.Parameter.VAR_KEYWORD for parameter in parameters.values()):",
        "        return func(**kwargs)",
        "    filtered_kwargs = {key: value for key, value in kwargs.items() if key in parameters}",
        "    return func(**filtered_kwargs)",
        "",
        "def load_shared_instruction_subset(args: argparse.Namespace) -> list[str]:",
        "    return ['train-row']",
        "",
        "def load_benchmark_examples(args: argparse.Namespace) -> Dict[str, list[dict[str, str]]]:",
        "    return {'benchmark_task_a': [{'answer': 'A'}]}",
        "",
        "def run_baseline_first_recipe_loop(args, device, train_dataset, eval_examples):",
        "    return [{'recipe_id': 'lora', 'train_dataset': train_dataset, 'eval_examples': eval_examples}]",
        "",
        "def _execute_baseline_first_workflow(args: argparse.Namespace, runtime_context: Mapping[str, Any]) -> list[dict[str, Any]]:",
        "    workflow = run_baseline_first_recipe_loop",
        "    device = runtime_context['device']",
        "    model_name = _get_arg(args, \"model_name\", _get_arg(args, \"base_model\", DEFAULT_BASE_MODEL))",
        "    common_kwargs = {",
        "        \"args\": args,",
        "        \"runtime_context\": runtime_context,",
        "        \"device\": device,",
        "        \"model_name\": model_name,",
        "        \"recipes\": globals().get(\"ADAPTER_RECIPES\", globals().get(\"RECIPE_CONFIGS\", None)),",
        "    }",
        "    workflow_output = _call_with_compatible_signature(workflow, **common_kwargs)",
        "    return list(workflow_output)",
        "",
        "def assemble_experiment_metrics(argv: Optional[Sequence[str]] = None) -> list[dict[str, Any]]:",
        "    args = _parse_orchestration_args(argv)",
        "    runtime_context = _initialize_orchestration_runtime(args)",
        "    return _execute_baseline_first_workflow(args, runtime_context)",
        "",
        "if __name__ == '__main__':",
        "    payload = assemble_experiment_metrics(argparse.Namespace(metrics_path='metrics.json'))",
        "    assert payload[0]['train_dataset'] == ['train-row']",
        "    assert payload[0]['eval_examples']['benchmark_task_a'][0]['answer'] == 'A'",
        ""
      ].join("\n"),
      "utf8"
    );

    const repair = await repairPythonOrchestrationArgumentSurface(scriptPath);
    const repairedSource = readFileSync(scriptPath, "utf8");
    expect(repair.repaired).toBe(true);
    expect(repairedSource).toContain("if isinstance(argv, argparse.Namespace):");
    expect(repairedSource).toContain("def _autolabos_prepare_workflow_train_dataset");
    expect(repairedSource).toContain("\"train_dataset\": train_dataset");
    execFileSync("python3", [scriptPath]);
  });

  it("repairs baseline-first recipe study workflow inputs and raw_results metrics payload alias", async () => {
    const workspace = mkdtempSync(path.join(os.tmpdir(), "autolabos-implement-baseline-recipe-inputs-"));
    tempDirs.push(workspace);
    const scriptPath = path.join(workspace, "experiment.py");
    writeFileSync(
      scriptPath,
      [
        "from __future__ import annotations",
        "",
        "import argparse",
        "import json",
        "from pathlib import Path",
        "from typing import Any, Dict, Mapping, Optional, Sequence",
        "",
        "DEFAULT_MAX_TRAIN_EXAMPLES = 2",
        "DEFAULT_MAX_EVAL_EXAMPLES = 1",
        "DEFAULT_MAX_SEQ_LENGTH = 16",
        "DEFAULT_LEARNING_RATE = 1e-4",
        "DEFAULT_NUM_BOOTSTRAP_SAMPLES = 0",
        "MAX_ALLOWED_TRAIN_EXAMPLES = 8",
        "SEED = 42",
        "",
        "def _get_arg(args, name, default=None):",
        "    return getattr(args, name, default)",
        "",
        "def _bounded_positive_int(value, default, cap=None):",
        "    parsed = int(value if value is not None else default)",
        "    if cap is not None:",
        "        parsed = min(parsed, int(cap))",
        "    return max(1, parsed)",
        "",
        "def detect_device():",
        "    return 'cpu'",
        "",
        "def load_tokenizer(model_name, args=None):",
        "    return {'tokenizer_for': model_name}",
        "",
        "def build_instruction_training_dataset(tokenizer, max_train_examples, max_seq_length, seed, **kwargs):",
        "    return ([{'text': 'train', 'tokenizer': tokenizer, 'limit': max_train_examples}], {'seed': seed})",
        "",
        "def load_evaluation_examples(max_eval_examples, seed, **kwargs):",
        "    return {'benchmark_task_a': [{'answer': 'A', 'limit': max_eval_examples, 'seed': seed}]}",
        "",
        "def _call_with_supported_kwargs(function, **kwargs):",
        "    import inspect",
        "    signature = inspect.signature(function)",
        "    if any(param.kind == inspect.Parameter.VAR_KEYWORD for param in signature.parameters.values()):",
        "        return function(**kwargs)",
        "    accepted = {name: value for name, value in kwargs.items() if name in signature.parameters}",
        "    return function(**accepted)",
        "",
        "def execute_baseline_first_recipe_study(",
        "    args: argparse.Namespace,",
        "    train_dataset: Optional[Any],",
        "    eval_datasets: Mapping[str, Sequence[Mapping[str, Any]]],",
        "    device: Any,",
        ") -> Dict[str, Any]:",
        "    return {'train_dataset': train_dataset, 'eval_datasets': eval_datasets, 'device': device}",
        "",
        "run_recipe_comparison = execute_baseline_first_recipe_study",
        "",
        "def assemble_metrics_payload(args, raw_results, **kwargs):",
        "    return {'status': 'completed', 'raw_results': raw_results}",
        "",
        "def _execute_study_from_args(args: argparse.Namespace, output_dir: Path) -> Dict[str, Any]:",
        "    seed = _bounded_positive_int(_get_arg(args, 'seed', SEED), SEED)",
        "    max_train_examples = _bounded_positive_int(_get_arg(args, 'max_train_examples', DEFAULT_MAX_TRAIN_EXAMPLES), DEFAULT_MAX_TRAIN_EXAMPLES, MAX_ALLOWED_TRAIN_EXAMPLES)",
        "    max_eval_examples = _bounded_positive_int(_get_arg(args, 'max_eval_examples', DEFAULT_MAX_EVAL_EXAMPLES), DEFAULT_MAX_EVAL_EXAMPLES)",
        "    eval_batch_size = _bounded_positive_int(_get_arg(args, 'eval_batch_size', 1), 1)",
        "    train_batch_size = _bounded_positive_int(_get_arg(args, 'train_batch_size', 1), 1)",
        "    max_steps = _bounded_positive_int(_get_arg(args, 'max_steps', 1), 1)",
        "    max_seq_length = _bounded_positive_int(_get_arg(args, 'max_seq_length', DEFAULT_MAX_SEQ_LENGTH), DEFAULT_MAX_SEQ_LENGTH)",
        "    gradient_accumulation_steps = _bounded_positive_int(_get_arg(args, 'gradient_accumulation_steps', 1), 1)",
        "    num_bootstrap_samples = int(_get_arg(args, 'num_bootstrap_samples', DEFAULT_NUM_BOOTSTRAP_SAMPLES))",
        "    learning_rate = float(_get_arg(args, 'learning_rate', DEFAULT_LEARNING_RATE))",
        "    model_name = str(_get_arg(args, 'model_name', 'tiny-model'))",
        "    workflow_kwargs: Dict[str, Any] = {",
        "        \"args\": args,",
        "        \"output_dir\": output_dir,",
        "        \"model_name\": model_name,",
        "        \"max_train_examples\": max_train_examples,",
        "        \"max_eval_examples\": max_eval_examples,",
        "        \"eval_batch_size\": eval_batch_size,",
        "        \"train_batch_size\": train_batch_size,",
        "        \"gradient_accumulation_steps\": gradient_accumulation_steps,",
        "        \"max_steps\": max_steps,",
        "        \"max_seq_length\": max_seq_length,",
        "        \"learning_rate\": learning_rate,",
        "        \"num_bootstrap_samples\": num_bootstrap_samples,",
        "        \"seed\": seed,",
        "    }",
        "    workflow = run_recipe_comparison",
        "    workflow_result = _call_with_supported_kwargs(workflow, **workflow_kwargs)",
        "    return dict(workflow_result)",
        "",
        "def _write_metrics_from_result(args, workflow_result, metrics_path, output_dir):",
        "    payload_builder = assemble_metrics_payload",
        "    payload = _call_with_supported_kwargs(",
        "        payload_builder,",
        "        args=args,",
        "        workflow_result=workflow_result,",
        "        results=workflow_result,",
        "        output_dir=output_dir,",
        "        metrics_path=metrics_path,",
        "    )",
        "    return payload",
        "",
        "if __name__ == '__main__':",
        "    ns = argparse.Namespace(seed=7, max_train_examples=2, max_eval_examples=1)",
        "    result = _execute_study_from_args(ns, Path('.'))",
        "    payload = _write_metrics_from_result(ns, result, Path('metrics.json'), Path('.'))",
        "    assert result['train_dataset'][0]['text'] == 'train'",
        "    assert result['eval_datasets']['benchmark_task_a'][0]['answer'] == 'A'",
        "    assert result['device'] == 'cpu'",
        "    assert payload['raw_results']['device'] == 'cpu'",
        ""
      ].join("\n"),
      "utf8"
    );

    const repair = await repairPythonOrchestrationArgumentSurface(scriptPath);
    const repairedSource = readFileSync(scriptPath, "utf8");
    expect(repair.repaired).toBe(true);
    expect(repairedSource).toContain("def _autolabos_prepare_baseline_recipe_study_inputs");
    expect(repairedSource).toContain("\"train_dataset\": train_dataset");
    expect(repairedSource).toContain("raw_results=workflow_result");
    execFileSync("python3", [scriptPath]);
  });

