        "@dataclass",
        "class PreflightRecord:",
        "    ok: bool",
        "",
        "def _find_helper_by_name(candidates: Sequence[str], required_tokens: Sequence[str]) -> Optional[Any]:",
        "    for name in candidates:",
        "        helper = globals().get(name)",
