  it("prioritizes final CLI orchestration and locked grid executors before helper resolvers", async () => {
    const workspace = mkdtempSync(path.join(os.tmpdir(), "autolabos-final-cli-locked-grid-"));
    tempDirs.push(workspace);
    const scriptPath = path.join(workspace, "runner.py");

    writeFileSync(
      scriptPath,
      [
        "from __future__ import annotations",
        "import argparse",
        "import inspect",
        "import json",
        "from typing import Any, Dict, List, Tuple",
        "",
        "def run_baseline_first_locked_grid(args=None, **kwargs):",
        "    return {",
        "        'status': 'completed',",
        "        'condition_seed_rows': [",
        "            {'condition_marker': 'baseline_condition', 'seed': 42, 'status': 'completed', 'average_accuracy': 0.5}",
        "        ],",
        "    }",
        "",
        "def _build_experiment_invocation_option_pool_for_cli(args=None):",
        "    return {'stage': 'wrong_helper'}",
        "",
        "def _resolve_core_experiment_callable_for_cli() -> Any:",
        "    candidate_names = (",
        "        \"run_locked_condition_study\",",
        "        \"run_locked_lora_study\",",
        "        \"run_baseline_first_experiment\",",
        "    )",
        "    for candidate_name in candidate_names:",
        "        candidate = globals().get(candidate_name)",
        "        if callable(candidate):",
        "            return candidate",
        "    fuzzy_matches: List[Tuple[int, str, Any]] = []",
        "    for name, candidate in globals().items():",
        "        if not callable(candidate):",
        "            continue",
        "        lowered = str(name).lower()",
        "        score = 100",
        "        if 'lora' in lowered and ('study' in lowered or 'experiment' in lowered):",
        "            score = 2",
        "        if score < 100:",
        "            fuzzy_matches.append((score, str(name), candidate))",
        "    if fuzzy_matches:",
        "        fuzzy_matches.sort(key=lambda item: (item[0], item[1]))",
        "        return fuzzy_matches[0][2]",
        "    raise RuntimeError('Unable to resolve core experiment callable')",
        "",
        "def _invoke_experiment_callable_for_cli(experiment_callable: Any, option_pool: Dict[str, Any]) -> Any:",
        "    signature = inspect.signature(experiment_callable)",
        "    kwargs = {key: value for key, value in option_pool.items() if key in signature.parameters}",
        "    return experiment_callable(**kwargs)",
        "",
        "def orchestrate_experiment_run(args: argparse.Namespace) -> Dict[str, Any]:",
        "    option_pool = {'args': args}",
        "    experiment_callable = _resolve_core_experiment_callable_for_cli()",
        "    return _invoke_experiment_callable_for_cli(experiment_callable, option_pool)",
        "",
        "def _call_callable_with_optional_single_argument(func: Any, argument: Any) -> Any:",
        "    signature = inspect.signature(func)",
        "    required = [",
        "        parameter",
        "        for parameter in signature.parameters.values()",
        "        if parameter.default is inspect._empty",
        "        and parameter.kind in (inspect.Parameter.POSITIONAL_ONLY, inspect.Parameter.POSITIONAL_OR_KEYWORD)",
        "    ]",
        "    if len(required) <= 1:",
        "        return func(argument)",
        "    return func()",
        "",
        "def _parse_cli_args_for_entrypoint(argv=None):",
        "    return argparse.Namespace()",
        "",
        "def _invoke_cli_orchestrator(args: Any) -> Any:",
        "    candidate_names = (",
        "        \"_run_cli_orchestration\",",
        "        \"run_cli_orchestration\",",
        "        \"run_cli_experiment\",",
        "    )",
        "    for name in candidate_names:",
        "        func = globals().get(name)",
        "        if callable(func):",
        "            return _call_callable_with_optional_single_argument(func, args)",
        "    heuristic_candidates: List[Tuple[str, Any]] = []",
        "    for name, func in globals().items():",
        "        if not callable(func):",
        "            continue",
        "        if name in {",
        "            \"main\",",
        "            \"_invoke_cli_orchestrator\",",
        "            \"_parse_cli_args_for_entrypoint\",",
        "            \"_assemble_final_metrics\",",
        "            \"_persist_metrics_outputs\",",
        "        }:",
        "            continue",
        "        lowered = name.lower()",
        "        if 'cli' in lowered or 'orchestr' in lowered or 'experiment' in lowered or 'study' in lowered:",
        "            heuristic_candidates.append((name, func))",
        "    for _, func in sorted(heuristic_candidates, key=lambda item: item[0]):",
        "        try:",
        "            return _call_callable_with_optional_single_argument(func, args)",
        "        except TypeError:",
        "            continue",
        "    raise RuntimeError('No CLI orchestration function was found in the experiment runner.')",
        "",
        "def main():",
        "    payload = _invoke_cli_orchestrator(_parse_cli_args_for_entrypoint())",
        "    print(json.dumps(payload, sort_keys=True))",
        "",
        "if __name__ == '__main__':",
        "    main()",
        ""
      ].join("\n"),
      "utf8"
    );

    const before = JSON.parse(execFileSync("python3", [scriptPath], { cwd: workspace, encoding: "utf8" }));
    expect(before).toEqual({ stage: "wrong_helper" });

    const repair = await repairPythonFinalCliLockedGridResolverSurface(scriptPath);
    const repairedSource = readFileSync(scriptPath, "utf8");

    expect(repair.repaired).toBe(true);
    expect(repairedSource).toContain('"orchestrate_experiment_run"');
    expect(repairedSource).toContain('"run_baseline_first_locked_grid"');
    expect(repairedSource).toContain('"_resolve_core_experiment_callable_for_cli"');
    const after = JSON.parse(execFileSync("python3", [scriptPath], { cwd: workspace, encoding: "utf8" }));
    expect(after.condition_seed_rows).toHaveLength(1);
    expect(after.condition_seed_rows[0]).toMatchObject({
      condition_marker: "baseline_condition",
      seed: 42,
      status: "completed"
    });
  });

  it("materializes runtime inputs for ordered condition collectors", async () => {
    const workspace = mkdtempSync(path.join(os.tmpdir(), "autolabos-ordered-collector-inputs-"));
    tempDirs.push(workspace);
    const scriptPath = path.join(workspace, "runner.py");
    const metricsPath = path.join(workspace, "metrics.json");

    writeFileSync(
      scriptPath,
      [
        "from __future__ import annotations",
        "import argparse",
        "import inspect",
        "import json",
        "from pathlib import Path",
        "",
        "DEFAULT_BASE_MODEL = 'the configured fallback backbone'",
        "TASK_NAMES = ('benchmark_task_a', 'benchmark_task_b')",
        "TASK_DATASET_CONFIGS = {",
        "    'benchmark_task_a': {'dataset_name': 'ai2_arc', 'dataset_config': 'Benchmark Task A', 'train_split': 'train', 'validation_split': 'validation'},",
        "    'benchmark_task_b': {'dataset_name': 'benchmark_task_b', 'dataset_config': None, 'train_split': 'train', 'validation_split': 'validation'},",
        "}",
        "class DatasetDict(dict):",
        "    pass",
        "def load_dataset(dataset_name, dataset_config=None, split=None):",
        "    return [{'dataset_name': dataset_name, 'dataset_config': dataset_config, 'split': split}]",
        "def _resolve_first_callable(names):",
        "    for name in names:",
        "        candidate = globals().get(name)",
        "        if callable(candidate):",
        "            return candidate",
        "    return None",
        "def _call_with_supported_kwargs(func, **kwargs):",
        "    signature = inspect.signature(func)",
        "    filtered = {key: value for key, value in kwargs.items() if key in signature.parameters}",
        "    return func(**filtered)",
        "def collect_ordered_condition_results(*, output_root_dir: Path, base_model_name: str, device, task_datasets):",
        "    return [{",
        "        'base_model_name': base_model_name,",
        "        'device': str(device),",
        "        'task_names': sorted(task_datasets.keys()),",
        "        'arc_train_split': task_datasets['benchmark_task_a']['train'][0]['split'],",
        "        'benchmark_task_b_validation_split': task_datasets['benchmark_task_b']['validation'][0]['split'],",
        "    }]",
        "def _extract_raw_condition_records(output):",
        "    return output, {}",
        "def _build_runtime_namespace(args: argparse.Namespace, output_dir: Path, metrics_path: Path) -> argparse.Namespace:",
        "    namespace = argparse.Namespace(**vars(args))",
        "    namespace.output_dir = output_dir",
        "    namespace.output_root_dir = output_dir",
        "    namespace.metrics_path = metrics_path",
        "    return namespace",
        "def run_condition_grid_study(args: argparse.Namespace):",
        "    output_dir = Path(args.output_dir).resolve()",
        "    metrics_path = Path(args.metrics_path).resolve()",
        "    runtime_namespace = _build_runtime_namespace(args, output_dir=output_dir, metrics_path=metrics_path)",
        "    collector = _resolve_first_callable(",
        "        (",
        "            '_collect_ordered_condition_results',",
        "            'collect_ordered_condition_results',",
        "            'run_ordered_condition_collection',",
        "        )",
        "    )",
        "    if collector is None:",
        "        raise RuntimeError('Unable to locate the ordered-condition collection helper in the study runner.')",
        "",
        "    collection_output = _call_with_supported_kwargs(",
        "        collector,",
        "        args=runtime_namespace,",
        "        cli_args=runtime_namespace,",
        "        config=runtime_namespace,",
        "        runtime_config=runtime_namespace,",
        "        study_config=runtime_namespace,",
        "        output_dir=output_dir,",
        "        output_root_dir=output_dir,",
        "        metrics_path=metrics_path,",
        "        timeout_sec=args.timeout_sec,",
        "        seed=args.seed,",
        "    )",
        "    raw_condition_records, collection_metadata = _extract_raw_condition_records(collection_output)",
        "    metrics_path.write_text(json.dumps({'condition_results': raw_condition_records, 'metadata': collection_metadata}), encoding='utf-8')",
        "    return raw_condition_records",
        "def main():",
        "    parser = argparse.ArgumentParser()",
        "    parser.add_argument('--output-dir', required=True)",
        "    parser.add_argument('--metrics-path', required=True)",
        "    parser.add_argument('--base-model-name', default='the selected backbone')",
        "    parser.add_argument('--timeout-sec', type=int, default=60)",
        "    parser.add_argument('--seed', type=int, default=42)",
        "    run_condition_grid_study(parser.parse_args())",
        "if __name__ == '__main__':",
        "    main()",
        ""
      ].join("\n"),
      "utf8"
    );

    expect(() =>
      execFileSync(
        "python3",
        [scriptPath, "--output-dir", workspace, "--metrics-path", metricsPath],
        { cwd: workspace }
      )
    ).toThrow(/base_model_name/u);

    const repair = await repairPythonOrderedConditionCollectorRuntimeInputsSurface(scriptPath);
    const repairedSource = readFileSync(scriptPath, "utf8");

    expect(repair.repaired).toBe(true);
    expect(repairedSource).toContain("_autolabos_ordered_collector_runtime_inputs_marker");
    expect(repairedSource).toContain("collector_task_datasets = _autolabos_collector_task_datasets(runtime_namespace)");
    expect(repairedSource).toContain("base_model_name=collector_base_model_name");
    expect(repairedSource).toContain("task_datasets=collector_task_datasets");

    execFileSync(
      "python3",
      [scriptPath, "--output-dir", workspace, "--metrics-path", metricsPath],
      { cwd: workspace }
    );
    expect(JSON.parse(readFileSync(metricsPath, "utf8"))).toMatchObject({
      condition_results: [
        {
          arc_train_split: "train",
          base_model_name: "the selected backbone",
          benchmark_task_b_validation_split: "validation",
          task_names: ["benchmark_task_a", "benchmark_task_b"]
        }
      ]
    });
  });

