        "",
        "class PublicDatasetBundle:",
        "    def __init__(self):",
        "        self.train = [{'instruction': 'say hi'}]",
        "        self.benchmark_task_a = [{'answer': 'A'}]",
        "        self.benchmark_task_b = [{'label': 'B'}]",
        "",
        "def load_public_dataset_bundle(args):",
        "    assert args.seed == 42",
