        "            return [_mappingify(item) for item in value]",
        "        if isinstance(value, tuple):",
        "            return [_mappingify(item) for item in value]",
        "    return []",
        "",
        "def main() -> int:",
        "    runtime_config = SimpleNamespace(paths=SimpleNamespace(output_dir=Path('out')), base_model_override=None)",
